import{_ as a,o as t,c as b,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"制式不死斩","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/制式不死斩.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/制式不死斩.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/制式不死斩.md"};function o(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"制式不死斩",tabindex:"-1"},[n("制式不死斩 "),r("a",{class:"header-anchor",href:"#制式不死斩","aria-label":'Permalink to "制式不死斩"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001F")])])],-1),p('<h1 id="制式不死斩-1" tabindex="-1">制式不死斩 <a class="header-anchor" href="#制式不死斩-1" aria-label="Permalink to &quot;制式不死斩&quot;">​</a></h1><p>=====资源说明=====<br> 制式不死斩是属于适配每个等级的普通武士刀，其核心效果就是针对各种杀不死的存在，如果要针对任意杀不死的敌人可选择该武器。</p><p>制式不死斩<br> 制式不死斩是由某位存在为了针对一切不死存在而批量打造出来的武士刀，对各种类型不死存在具有强大的克制效果，并且由于是批量打造的，所以不同等级的不死斩都有出售,并且允许差价强化至更高等级的不死斩，而且提供除刀刃部分以外刀体结构的定制服务。</p><p>D级不死斩 D+500<br> 武器伤害：6L<br> 武器类型：武士刀<br> 对应专业：刀<br> 武器效果：破甲1 【法破】 斩断不死<br> 斩断不死：被不死斩杀死的存在无法通过B级及以下等级的复活能力进行复活。</p><p>C级不死斩 C+1000<br> 武器伤害：11L<br> 武器类型：武士刀<br> 对应专业：刀<br> 武器效果：破甲1 【法破】 斩断不死 追猎不死<br> 斩断不死：被不死斩杀死的存在无法通过A级及以下等级的复活能力进行复活。<br> 追猎不死：仅在手持武器的时候获得一种非线型感知，能感知到具有不死性的存在，而对不死性的定义为具有复活能力或超强自愈能力的存在。</p><p>B级不死斩 B+2000<br> 武器伤害：18L<br> 武器类型：武士刀<br> 对应专业：刀<br> 武器效果：破甲4【法破】【重伤】 斩断不死 追猎不死<br> 斩断不死：被不死斩杀死的存在无法通过S级及以下等级的复活能力进行复活,并且不死斩的每一次斩击都附带【重伤】的效果，这是一个B级诅咒来源的【重伤】效果。<br> 追猎不死：仅在手持武器的时候获得一种强非线型感知，能感知到具有不死性的存在，而对不死性的定义为具有复活能力或超强自愈能力的存在。</p><p>A级不死斩 A+4000<br> 武器伤害：27L+2<br> 武器类型：武士刀<br> 对应专业：刀<br> 武器效果：破甲10 破魔9【法破】【重伤】【8加骰】【湮灭】斩断不死 追猎不死<br> 斩断不死：被不死斩杀死的存在无法通过SS级及以下等级的复活能力进行复活,并且不死斩的每一次斩击都附带【重伤】的效果，这是一个A级诅咒来源的【重伤】效果。<br> 追猎不死：仅在手持武器的时候获得一种强非线型感知，能感知到具有不死性的存在，而对不死性的定义为具有复活能力或超强自愈能力的存在。</p><p>S级不死斩 S+8000<br> 武器伤害：38A+8<br> 武器类型：武士刀<br> 对应专业：刀<br> 武器效果：破甲10 破魔9【法破】【重伤】【8加骰】【湮灭】斩断不死 追猎不死 不死天敌<br> 斩断不死：被不死斩杀死的存在无法通过SSS级及以下等级的复活能力进行复活,并且不死斩的每一次斩击都附带【重伤】的效果，这是一个S级诅咒来源的【重伤】效果。<br> 追猎不死：仅在手持武器的时候获得一种强非线型感知，能感知到具有不死性的存在，而对不死性的定义为具有复活能力或超强自愈能力的存在。<br> 不死天敌:具有不死性的存在受到来自不死斩的伤害时，需要以强韧豁免对抗伤害数，豁免失败直接死亡，这是一个S级诅咒来源的【即死】效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const f=a(s,[["render",o]]);export{S as __pageData,f as default};
